// frontend/src/components/PlaceCard.js
import React from 'react';

const CROWD_CONFIG = {
  Low:    { bg:'#e8f8f2', text:'#085041', dot:'#1D9E75', bar:25 },
  Medium: { bg:'#fef8e8', text:'#7a4f00', dot:'#d4a017', bar:60 },
  High:   { bg:'#fdecea', text:'#7a1e1e', dot:'#e53935', bar:90 },
};

const CATEGORY_ICONS = {
  mall:'🛍️', cafe:'☕', gym:'💪', restaurant:'🍽️',
  park:'🌳', zoo:'🦁', cinema:'🎬', tourist:'🏛️',
};

const CATEGORY_LABELS = {
  mall:'Mall', cafe:'Cafe', gym:'Gym', restaurant:'Restaurant',
  park:'Park', zoo:'Zoo', cinema:'Cinema', tourist:'Tourist Place',
};

export default function PlaceCard({ place, prediction }) {
  const crowd  = prediction?.crowd_level || 'Medium';
  const config = CROWD_CONFIG[crowd] || CROWD_CONFIG.Medium;
  const score  = prediction?.crowd_score ?? 0;

  return (
    <div style={{ background:'#fff', borderRadius:'20px', padding:'20px', border:'1.5px solid #f0f0f0', boxShadow:'0 2px 16px rgba(0,0,0,0.05)', transition:'box-shadow .2s' }}>

      {/* Header */}
      <div style={{ display:'flex', justifyContent:'space-between', alignItems:'flex-start', marginBottom:'14px' }}>
        <div style={{ display:'flex', alignItems:'center', gap:'10px', flex:1, minWidth:0 }}>
          <div style={{ width:'44px', height:'44px', borderRadius:'12px', background:'#f7f8fc', display:'flex', alignItems:'center', justifyContent:'center', fontSize:'22px', flexShrink:0 }}>
            {CATEGORY_ICONS[place.category] || '📍'}
          </div>
          <div style={{ minWidth:0 }}>
            <div style={{ fontWeight:'700', fontSize:'15px', color:'#1a1a2e', whiteSpace:'nowrap', overflow:'hidden', textOverflow:'ellipsis' }}>
              {place.name}
            </div>
            <div style={{ fontSize:'12px', color:'#999', marginTop:'2px' }}>
              {CATEGORY_LABELS[place.category] || place.category}
              {place.address ? ` · ${place.address.split(',')[0]}` : ''}
            </div>
          </div>
        </div>
        {/* Crowd badge */}
        <div style={{ display:'flex', alignItems:'center', gap:'5px', padding:'5px 11px', borderRadius:'20px', background:config.bg, color:config.text, fontSize:'12px', fontWeight:'700', flexShrink:0, marginLeft:'8px' }}>
          <span style={{ width:'7px', height:'7px', borderRadius:'50%', background:config.dot, display:'inline-block' }}/>
          {crowd}
        </div>
      </div>

      {/* Distance */}
      {place.distance_label && (
        <div style={{ display:'inline-flex', alignItems:'center', gap:'5px', background:'#f0f4ff', color:'#3a5bd9', padding:'5px 12px', borderRadius:'20px', fontSize:'12px', fontWeight:'600', marginBottom:'12px', border:'1px solid #d8e0ff' }}>
          🗺️ {place.distance_label}
        </div>
      )}

      {/* Crowd bar */}
      <div style={{ marginBottom:'12px' }}>
        <div style={{ display:'flex', justifyContent:'space-between', marginBottom:'5px' }}>
          <span style={{ fontSize:'11px', color:'#999', fontWeight:'600', textTransform:'uppercase', letterSpacing:'0.5px' }}>Crowd Level</span>
          <span style={{ fontSize:'11px', color:'#999' }}>{prediction?.active_users ?? 0} people · {score}%</span>
        </div>
        <div style={{ height:'8px', background:'#f0f0f0', borderRadius:'6px', overflow:'hidden' }}>
          <div style={{ height:'100%', borderRadius:'6px', background:config.dot, width:`${score}%`, transition:'width .6s ease' }}/>
        </div>
      </div>

      {/* Trend */}
      {prediction?.trend && (
        <div style={{ display:'inline-flex', alignItems:'center', gap:'5px', fontSize:'12px', color:'#888', marginBottom:'12px', background:'#f7f8fc', padding:'4px 10px', borderRadius:'20px' }}>
          {prediction.trend}
        </div>
      )}

      {/* Metrics */}
      <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr 1fr', gap:'8px' }}>
        {[
          { label:'Wait Time', value:prediction?.waiting_time  ?? 'N/A', icon:'⏱️' },
          { label:'Avg Cost',  value:prediction?.estimated_cost?? 'N/A', icon:'💰' },
          { label:'Best Time', value:prediction?.best_time     ?? 'N/A', icon:'🕐' },
        ].map(m=>(
          <div key={m.label} style={{ background:'#f7f8fc', borderRadius:'12px', padding:'10px 8px', textAlign:'center' }}>
            <div style={{ fontSize:'16px', marginBottom:'3px' }}>{m.icon}</div>
            <div style={{ fontSize:'11px', fontWeight:'700', color:'#1a1a2e', whiteSpace:'nowrap', overflow:'hidden', textOverflow:'ellipsis' }}>{m.value}</div>
            <div style={{ fontSize:'10px', color:'#bbb', marginTop:'2px', textTransform:'uppercase', letterSpacing:'0.4px' }}>{m.label}</div>
          </div>
        ))}
      </div>

      <div style={{ marginTop:'10px', fontSize:'11px', color:'#ccc', textAlign:'right' }}>
        🤖 Based on real-world crowd patterns
      </div>
    </div>
  );
}
